class Solution {
    public String sortString(String s) {
        StringBuilder result = new StringBuilder();
        while (s.length() > 0) {
            char min = s.charAt(0);
            for (int i = 1; i < s.length(); i++) {
                if (s.charAt(i) < min) {
                    min = s.charAt(i);
                }
            }
            result.append(min);
            s = s.replaceFirst(String.valueOf(min), "");
            char max = min;
            for (int i = 0; i < s.length(); i++) {
                if (s.charAt(i) > max) {
                    max = s.charAt(i);
                }
            }
            result.append(max);
            s = s.replaceFirst(String.valueOf(max), "");
        }
        return result.toString();
    }
}
